mapper.select:
/*SelfHpcMgmtMapper.getRcpSelfHpcListExcel*/ SELECT DISTINCT REQ.REQUEST_KEY , SUB.CONTRACT_NUM , SUB.LST_COM_ACTV_DATE , SUB.SUB_LINK_NAME , SUB.SUBSCRIBER_NO , SUB.OPEN_AGNT_CD , FN_GET_ORGNM(SUB.OPEN_AGNT_CD) AS OPEN_AGNT_NM , AUTH.MOBILE_NO /*NICE 본인인증번호*/ , AUTH.MOBILE_CO /*NICE 본인인증통신사*/ , TO_CHAR(AUTH.AUTH_TIME, 'YYYY-MM-DD HH24:MI:SS') AS AUTH_TIME /*NICE 본인인증일시*/ , FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) AS AGE , REQ.CSTMR_TYPE , CRYPTO_AES256.DEC_AES(SUB.USER_SSN) AS USER_SSN , REQ.FST_RATE_NM /*최초요금제 */ , CASE WHEN REQ.CSTMR_TYPE = 'JP' OR REQ.CSTMR_TYPE = 'PP' THEN '' ELSE SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) END GENDER /*성별 */ , BAN.BAN_ADR_PRIMARY_LN || ' ' || BAN.BAN_ADR_SECONDARY_LN AS ADDR , CASE WHEN MSD.REQ_USIM_SN IS NOT NULL THEN '직영온라인' ELSE FN_GET_ORGNM(PUM.ORGN_ID) END AS USIM_ORG_NM /*유심접점*/ , FN_GET_ORGNM(PUM.ORGN_ID) AS FST_USIM_ORG_NM /*최초유심접점*/ , AUTH.HPC_STAT , FN_GET_CODENM('RCP9040', AUTH.HPC_STAT) AS HPC_STAT_NM /*해피콜 여부*/ , AUTH.FST_HPC_RST , FN_GET_CODENM('CMN0066', AUTH.FST_HPC_RST) AS FST_HPC_RST_NM /*1차해피콜결과*/ , AUTH.FST_HPC_RMK /*1차해피콜비고*/ , FN_GET_USRNM(AUTH.FST_HPC_USR_ID) AS FST_HPC_USR_NM /*1차해피콜처리자*/ , TO_CHAR(AUTH.FST_HPC_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS FST_HPC_DTTM /*1차해피콜처리일시*/ , AUTH.SND_HPC_RST , FN_GET_CODENM('CMN0066', AUTH.SND_HPC_RST) AS SND_HPC_RST_NM /*2차해피콜결과*/ , AUTH.SND_HPC_RMK /*2차해피콜비고*/ , FN_GET_USRNM(AUTH.SND_HPC_USR_ID) AS SND_HPC_USR_NM /*2차해피콜처리자*/ , TO_CHAR(AUTH.SND_HPC_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS SND_HPC_DTTM /*2차해피콜처리일시*/ , AUTH.THD_HPC_RST , FN_GET_CODENM('CMN0066', AUTH.THD_HPC_RST) AS THD_HPC_RST_NM /*3차해피콜결과*/ , AUTH.THD_HPC_RMK /*3차해피콜비고*/ , FN_GET_USRNM(AUTH.THD_HPC_USR_ID) AS THD_HPC_USR_NM /*3차해피콜처리자*/ , TO_CHAR(AUTH.THD_HPC_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS THD_HPC_DTTM /*3차해피콜처리일시*/ , AUTH.HPC_RST , FN_GET_CODENM('RCP9041', AUTH.HPC_RST) AS HPC_RST_NM /*해피콜결과*/ , DECODE(ACEN.REQ_STATUS, 'N', '요청대기', 'Y', '요청완료', NULL) AS ACEN_REQ_STATUS_NM /*A'Cen 요청상태*/ , ACEN.RMK AS ACEN_RST ,(SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'AcenSelfRslt' AND DTL_CD = ACEN.RMK) AS ACEN_RST_NM /*A'Cen 결과*/ FROM MSP_JUO_SUB_INFO SUB , MSP_REQUEST_DTL REQ , NMCP_SELF_SMS_AUTH@DL_MCP AUTH , MSP_PARTNER_USIM_MST PUM , NMCP_USIM_BUY_TXN@DL_MCP MSD , NMCP_ACEN_REQ@DL_MCP ACEN , MSP_JUO_BAN_INFO BAN WHERE SUB.CONTRACT_NUM = REQ.CONTRACT_NUM AND REQ.REQUEST_KEY = AUTH.REQUEST_KEY AND SUB.ON_OFF_TYPE IN ('5','7') AND REQ.OPER_TYPE = 'NAC3' AND REQ.FST_USIM_NO = PUM.USIM_NO(+) AND SUB.ICC_ID = MSD.REQ_USIM_SN(+) AND AUTH.REQUEST_KEY = ACEN.REQUEST_KEY(+) AND SUB.BAN = BAN.BAN
AND SUB.LST_COM_ACTV_DATE BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND SUB.SUB_LINK_NAME = #{searchName}
AND SUB.CONTRACT_NUM = #{searchName}
AND SUB.SUBSCRIBER_NO = #{searchName}
AND AUTH.HPC_STAT = #{srchHpcStat}
AND AUTH.HPC_RST = #{srchHpcRst}
AND ACEN.RMK = #{srchAcenRst}
ORDER BY SUB.LST_COM_ACTV_DATE
